head.script:
//==================================================================================================================
// id       : op_204_02_08p 
// 이름     : 하역작업지시번호검색
// 경로     : 물류/하역(인천)/실적/정규직실적확인
// 작 성 자 : 조성빈
// 작 업 일 : 2026-02-03
// 사용계정 : 내부
// 비고     : 
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//==================================================================================================================
scwin.loUpperLobranCd;
scwin.userClsCd;
scwin.clntNo;
scwin.clntNm;
scwin.vCurDate;
scwin.paramTitle;
scwin.arrRtnVal;
scwin.arrOptCnd;
scwin.strQueryId;
scwin.strOnCloseTF;
scwin.strExistTF;
scwin.strAllSearchTF;
scwin.strWrkDtTF;
scwin.strCurDate;
scwin.strCvsslMgntNo;
scwin.strWrkPlCd;
scwin.strWrkIndictClsCd;

scwin.onpageload = function() {
	scwin.loUpperLobranCd   = $c.data.getMemInfo("loUpperLobranCd"); // 물류상위점소코드
	scwin.userClsCd         = $c.data.getMemInfo("userClsCd"); // 사용자구분코드
	scwin.clntNo            = $c.data.getMemInfo("clntNo"); // 거래처번호
	scwin.clntNm            = $c.data.getMemInfo("clntNm"); // 거래처명
	scwin.vCurDate          = $c.date.getServerDateTime("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
	scwin.paramTitle        = $c.data.getParameter("paramTitle");

	if (scwin.loUpperLobranCd   == null) scwin.loUpperLobranCd = "";
	if (scwin.userClsCd         == null) scwin.userClsCd = "";
	if (scwin.clntNo            == null) scwin.clntNo = "";
	if (scwin.clntNm            == null) scwin.clntNm = "";

    scwin.arrRtnVal 		= new Array(); 	//Return Value
    scwin.arrOptCnd 		= new Array("", "", "", "", "", "", "", "", "", ""); // Where절의 추가 조건
    scwin.strQueryId 		= ""; 		 	//XML SELECT ID
    scwin.strOnCloseTF 	    = "";     		// Result건수 1건일경우 AutoClose 여부
    scwin.strExistTF 		= "";     		// 중복체크여부
    scwin.strAllSearchTF 	= "";     		// 전체검색 허용여부
    scwin.strWrkDtTF 		= "";			// 작업일자 disable 여부
    scwin.strCurDate 		= "";			//오늘날짜
    scwin.strCvsslMgntNo 	= "";			//본선관리번호
    scwin.strWrkPlCd        = "";           //작업장코드
    scwin.strWrkIndictClsCd = "";

    const codeOptions = [ 
        {
            method: "getLuxeComboData", 
            param1: "DsCommonEBC", 
            param2: "retriveWrkIndictClsCdList",
            // param3: ["CMP"],
            compID: "acb_wrkIndictClsCd" 
        }
    ];
    $c.data.setGauceUtil(codeOptions, scwin.setGauceComboCallBack);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":50});
};

scwin.setGauceComboCallBack = async function(){
    acb_wrkIndictClsCd.addItem("전체", "", "", 0);
    acb_wrkIndictClsCd.setSelectedIndex(0);

    //점소 조회
    var rs = await $c.sbm.execute(sbm_lobran);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        ds_lobran.setJSON(rs.responseJSON.GAUCE);
        ds_lobran.sort("lobranCd", 0);
    };

	scwin.arrParent = $p.getAllParameter().paramData.data;
	scwin.iDispCnt  = "";

	// lblTitle.innerHTML = scwin.arrParent[0][0];
    $c.data.setPopupTitle(scwin.arrParent[0][0]);
	txt_cndTitleCd.setValue(scwin.arrParent[0][1]);
    txt_cndTitleNm  
	txt_cndTitleNm.setValue(scwin.arrParent[0][2]);

	scwin.strQueryId            = scwin.arrParent[0][3];
	scwin.strOnCloseTF          = scwin.arrParent[0][4];
	scwin.iDispCnt              = scwin.arrParent[0][5];
	scwin.strExistTF            = scwin.arrParent[0][6];
	scwin.strAllSearchTF        = scwin.arrParent[0][7];
	scwin.strWrkDtTF	        = scwin.arrParent[0][8];

	scwin.strWrkIndictClsCd 	= scwin.arrParent[1][0];
	scwin.strCurDate		    = scwin.arrParent[1][1];	// 오늘날짜

	ds_hidden.set("hd_wrkIndictNo", scwin.arrParent[1][2]);
	scwin.strCvsslMgntNo        = scwin.arrParent[1][3];
	scwin.strWrkPlCd            = scwin.arrParent[1][4];
	ica_wrkDt.setValue(scwin.arrParent[1][1]);

    acb_lobran.setValue(scwin.loUpperLobranCd);
	acb_wrkIndictClsCd.setValue(scwin.strWrkIndictClsCd);

    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    acb_lobran.setValue(scwin.loUpperLobranCd);
	acb_wrkIndictClsCd.setValue(scwin.strWrkIndictClsCd);
	ica_wrkDt.setValue(scwin.strCurDate);

};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
	if ("P" == acb_wrkIndictClsCd.getValue()) {
	  	if (!await $c.gus.cfValidate([acb_wrkIndictClsCd])) { // 본선/작업장구분, 본선관리번호
	  		return;
		}
	} else if ("Y" == acb_wrkIndictClsCd.getValue()) {
	  	if (!await $c.gus.cfValidate([acb_wrkIndictClsCd, ica_wrkDt])) { // 본선/작업장구분, 작업일자
	  		return;
		}
	} else {
		// 검색조건 필수 입력 체크 - 작업지시구분,작업일자
	  	if (!await $c.gus.cfValidate([ica_wrkDt])) {
	  		return;
		}
	}

	ds_WrkIndictNoQueryCondition.removeAll();

	var rowIndex = ds_WrkIndictNoQueryCondition.insertRow();
    ds_WrkIndictNoQueryCondition.setRowPosition(rowIndex);

	ds_WrkIndictNoQueryCondition.setCellData(ds_WrkIndictNoQueryCondition.getRowPosition(), "wrkIndictNo", ds_hidden.get("hd_wrkIndictNo"));    // 작업지시번호
	ds_WrkIndictNoQueryCondition.setCellData(ds_WrkIndictNoQueryCondition.getRowPosition(), "wrkIndictClsCd", acb_wrkIndictClsCd.getValue());  	// 작업지시구분
	ds_WrkIndictNoQueryCondition.setCellData(ds_WrkIndictNoQueryCondition.getRowPosition(), "wrkDt", ica_wrkDt.getValue());  					// 작업일자
	ds_WrkIndictNoQueryCondition.setCellData(ds_WrkIndictNoQueryCondition.getRowPosition(), "cvsslMgntNo", scwin.strCvsslMgntNo);  				// 본선관리번호
	ds_WrkIndictNoQueryCondition.setCellData(ds_WrkIndictNoQueryCondition.getRowPosition(), "lobranCd", acb_lobran.getValue());  			    // 점소코드
	ds_WrkIndictNoQueryCondition.setCellData(ds_WrkIndictNoQueryCondition.getRowPosition(), "wrkPlCd", scwin.strWrkPlCd);  			            // 작업장코드
    $c.sbm.execute(sbm_searchWrkIndictNo);
}

//-------------------------------------------------------------------------
// Grid에서 선택된 Row의 Value
//-------------------------------------------------------------------------
scwin.f_rtnValue = function (row) {
	scwin.arrRtnVal[0]  = ds_WrkIndictNo.getCellData(row, "wrkIndictNo");       //작업지시번호
	scwin.arrRtnVal[1]  = ds_WrkIndictNo.getCellData(row, "wrkIndictClsCd");    //작업지시구분코드
	scwin.arrRtnVal[2]  = ds_WrkIndictNo.getCellData(row, "wrkIndictClsNm");    //작업지시구분명
	scwin.arrRtnVal[3]  = ds_WrkIndictNo.getCellData(row, "cvsslNmYardNm");     //본선명장치장명
	scwin.arrRtnVal[4]  = ds_WrkIndictNo.getCellData(row, "wrkDt");             //작업일자
	scwin.arrRtnVal[5]  = ds_WrkIndictNo.getCellData(row, "shiftClsCd");        //SHIFT구분코드
	scwin.arrRtnVal[6]  = ds_WrkIndictNo.getCellData(row, "shiftClsNm");        //SHIFT구분명
	scwin.arrRtnVal[7]  = ds_WrkIndictNo.getCellData(row, "cvsslMgntNo");       //본선관리번호
	scwin.arrRtnVal[8]  = ds_WrkIndictNo.getCellData(row, "cvsslNmYardCd");     //선박코드장치장코드
	scwin.arrRtnVal[9]  = ds_WrkIndictNo.getCellData(row, "pchsDeptCd");        //매입부서코드
	scwin.arrRtnVal[10] = ds_WrkIndictNo.getCellData(row, "wrkStDt");           //작업시작일자
	scwin.arrRtnVal[11] = ds_WrkIndictNo.getCellData(row, "wrkStHh");           //작업시작시간
	scwin.arrRtnVal[12] = ds_WrkIndictNo.getCellData(row, "wrkEndDt");          //작업종료일자
	scwin.arrRtnVal[13] = ds_WrkIndictNo.getCellData(row, "wrkEndHh");          //작업종료시간
	scwin.arrRtnVal[14] = ds_WrkIndictNo.getCellData(row, "pchsDeptNm");        //매입부서명
	scwin.arrRtnVal[15] = ds_WrkIndictNo.getCellData(row, "lobranCd");          //점소코드

	var returnValue = scwin.arrRtnVal;
    $c.win.closePopup(returnValue);
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve()
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};

scwin.sbm_searchWrkIndictNo_submit = function (e) {

};

scwin.sbm_searchWrkIndictNo_submitdone = async function (e) {
    var rowCnt = ds_WrkIndictNo.getRowCount()
    txt_totalRows.setValue(rowCnt);

	if (scwin.strExistTF == "T") {
        var returnValue = rowCnt;
        $c.win.closePopup(returnValue);
		return ;
	} else {
		if (rowCnt == 1	&& scwin.strOnCloseTF == "T") {
			scwin.f_rtnValue(0);
			return;
		}
		if (rowCnt == 0	) {
			await $c.gus.cfAlertMsg(MSG_CM_WRN_002);	// 조회결과가 존재하지 않습니다
			return; 
		}
	}
	ds_WrkIndictNo.setRowPosition(0);
	gr_popup.focus();
};

scwin.sbm_searchWrkIndictNo_submiterror = function (e) {

};

scwin.gr_popup_oncelldblclick = function (row, columnIndex, columnId) {
	scwin.f_rtnValue(row);
};
